+import { Pattern } from './types/Pattern';
+import { MatchEach } from './types/MatchEach';
+import * as symbols from './internals/symbols';
+import { matchPattern } from './internals/helpers';
+import { NonExhaustiveError } from './errors';
+
+type Clause = { patterns: Pattern<any>[]; predicate?: (value: any) => unknown; handler: (selection: unknown, value: any) => unknown };
+type Action = { type: 'clause'; clause: Clause } | { type: 'tap'; callback: (result: unknown) => unknown };
+
+/** Creates a pattern matching expression which collects every matching result. */
+export function matchEach<const input, output = symbols.unset>(value: input): MatchEach<input, output>;
+export function matchEach<input, output = symbols.unset>(): MatchEach<input, output>;
+export function matchEach<input, output = symbols.unset>(value?: input): MatchEach<input, output> {
+  return new MatchEachExpression<output>([]) as any;
+}
+
+class MatchEachExpression<output> {
+  constructor(private actions: Action[]) {}
+
+  with(...args: any[]) {
+    const handler = args[args.length - 1];
+    const patterns: Pattern<any>[] = [args[0]];
+    let predicate: ((value: any) => unknown) | undefined;
+    if (args.length === 3 && typeof args[1] === 'function') predicate = args[1];
+    else if (args.length > 2) patterns.push(...args.slice(1, -1));
+    return new MatchEachExpression<output>([...this.actions, { type: 'clause', clause: { patterns, predicate, handler } }]);
+  }
+
+  when(predicate: (value: any) => unknown, handler: (value: any) => output) {
+    return this.with(symbols.anonymousSelectKey as any, predicate, (_: unknown, value: any) => handler(value));
+  }
+
+  tap(callback: (result: output) => unknown) {
+    return new MatchEachExpression<output>([...this.actions, { type: 'tap', callback }]);
+  }
+
+  private evaluate(input: unknown, partial: boolean, fallback?: (value: unknown) => output): output[] | undefined {
+    const results: output[] = [];
+    for (const action of this.actions) {
+      if (action.type === 'tap') {
+        results.forEach((result) => action.callback(result));
+        continue;
+      }
+      const { patterns, predicate, handler } = action.clause;
+      let selection: unknown = input;
+      let matched = false;
+      for (const pattern of patterns) {
+        let hasSelections = false;
+        const selected: Record<string, unknown> = {};
+        if (matchPattern(pattern, input, (key, selectedValue) => { hasSelections = true; selected[key] = selectedValue; })) {
+          selection = hasSelections ? (symbols.anonymousSelectKey in selected ? selected[symbols.anonymousSelectKey] : selected) : input;
+          matched = true;
+          break;
+        }
+      }
+      if (matched && (!predicate || predicate(input))) results.push(handler(selection, input) as output);
+    }
+    if (results.length) return results;
+    if (fallback) return [fallback(input)];
+    if (partial) return undefined;
+    throw new NonExhaustiveError(input);
+  }
+
+  otherwise(handler: (value: unknown) => output) { return this.evaluate(undefined, false, handler)!; }
+  exhaustive(handler?: (value: unknown) => output) { return this.evaluate(undefined, false, handler); }
+  run() { return this.evaluate(undefined, false)!; }
+  toFunction() { return (input: unknown) => this.evaluate(input, false)!; }
+  toPartialFunction() { return (input: unknown) => this.evaluate(input, true); }
+  toExhaustiveFunction() { return (input: unknown) => this.evaluate(input, false)!; }
+  returnType() { return this; }
+  narrow() { return this; }
+}
